-- Verification: every diff should be 0.
SELECT COALESCE(s.ym, d.ym) AS ym, s.cnt AS src_cnt, d.cnt AS dst_cnt, d.cnt - s.cnt AS diff
FROM (SELECT DATE_FORMAT(part_month, '%Y%m') ym, COUNT(*) cnt FROM MIHDB_ODS.jj_comm_jc_result_all_Encry GROUP BY 1) s
LEFT JOIN (SELECT DATE_FORMAT(part_month, '%Y%m') ym, COUNT(*) cnt FROM MIHDB_ODS.jj_comm_jc_result_all_Encry_new GROUP BY 1) d ON s.ym = d.ym
ORDER BY ym;

SELECT 'src_total', COUNT(*) FROM MIHDB_ODS.jj_comm_jc_result_all_Encry;
SELECT 'dst_total', COUNT(*) FROM MIHDB_ODS.jj_comm_jc_result_all_Encry_new;
SELECT 'id_check', COUNT(*), COUNT(id), SUM(CASE WHEN id IS NULL THEN 1 ELSE 0 END), MIN(id), MAX(id) FROM MIHDB_ODS.jj_comm_jc_result_all_Encry_new;

